PATCHED AfdSanCancelAccept @ 0x1C007F120 (fix, feature-gated):

    if ((*(uint*)(conn+0x08) & 0x800) == 0) {
        if (EvaluateCurrentState(&g_Feature_556471608_60363862)) {
            *(byte*)(conn+0x91) = 1;                 // teardown flag
            for (head = conn+0x70; *head != head; ) { // drain ALL pending IRPs
                entry = *head;
                *head = entry->Flink; entry->Flink->Blink = head;
                entry->Flink = 0; entry->Blink = drain; drain = entry;
            }
        } else {
            // old path retained: reset immediately, no drain
            AfdDereferenceEndpointInline(*(void**)(conn+0x50));
            memset(conn+0x50, 0, 0x48);
            *(uint*)(conn+0x08) = 0; *(ushort*)conn = 0xAFD0; *(byte*)(conn+0x02) = 1;
        }
    }
    // release lock; then, if feature enabled, complete each drained IRP with
